localparam STATE0 = 4'b0100, STATE1 = 4'b0001, STATE2 = 4'b1000, STATE3 = 4'b0010;
(* fsm_encoding="auto" *) reg [3:0] state;
always @(posedge clk) case(state) STATE0: state <= STATE1; STATE1: state <= STATE2; STATE2: state <= STATE3; STATE3: state <= STATE0; endcase

localparam STATE0 = 4'b0100;
reg [3:0] state = STATE0;
always @(posedge strobe) case(state) STATE0: state <= STATE1; endcase
